#include <stdio.h>
#include <stdlib.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N, k; scanf("%d %d", &N, &k);
        int *a = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &a[i]);
        int *deque = (int*)malloc(N * sizeof(int)); // store indices of even numbers
        int front = 0, back = -1;
        for (int i = 0; i < N; ++i) {
            if (a[i] % 2 == 0) {
                deque[++back] = i;
            }
            if (i >= k - 1) {
                int start = i - k + 1;
                while (front <= back && deque[front] < start) ++front;
                if (front <= back) {
                    printf("%d", a[deque[front]]);
                } else {
                    printf("-1");
                }
                if (i != N - 1) printf(" ");
            }
        }
        printf("\n");
        free(a);
        free(deque);
    }
    return 0;
}

