import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder out = new StringBuilder();
        for (int tc = 0; tc < T; tc++) {
            int N = fs.nextInt();
            int k = fs.nextInt();
            int[] a = new int[N];
            for (int i = 0; i < N; i++) a[i] = fs.nextInt();
            ArrayDeque<Integer> dq = new ArrayDeque<>();
            for (int i = 0; i < N; i++) {
                if (a[i] % 2 == 0) dq.addLast(i);
                if (i >= k - 1) {
                    int start = i - k + 1;
                    while (!dq.isEmpty() && dq.peekFirst() < start) dq.pollFirst();
                    if (!dq.isEmpty()) out.append(a[dq.peekFirst()]);
                    else out.append(-1);
                    if (i != N - 1) out.append(' ');
                }
            }
            if (tc != T - 1) out.append('\n');
        }
        System.out.print(out.toString());
    }

    // Fast scanner for large input
    static class FastScanner {
        private final BufferedInputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream is) { in = new BufferedInputStream(is); }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return val * sign;
        }
    }
}

