#!/usr/bin/env python3
import sys

def solve():
    data = list(map(int, sys.stdin.read().split()))
    if not data:
        return
    idx = 0
    T = data[idx]; idx += 1
    out_lines = []
    for _ in range(T):
        N = data[idx]; k = data[idx+1]; idx += 2
        a = data[idx:idx+N]; idx += N
        from collections import deque
        dq = deque()  # store indices of even numbers
        res = []
        for i, val in enumerate(a):
            if val % 2 == 0:
                dq.append(i)
            if i >= k - 1:
                start = i - k + 1
                while dq and dq[0] < start:
                    dq.popleft()
                if dq:
                    res.append(str(a[dq[0]]))
                else:
                    res.append(str(-1))
        out_lines.append(' '.join(res))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

